import type { Router, RouteRecordRaw } from 'vue-router'
import { host as defaultHost, on as defaultOn, setLocalRouter } from '@wippy-fe/proxy'
import { createMemoryHistory, createRouter } from 'vue-router'

export interface CreateAppRouterOptions {
  /**
   * Initial route path to prime history with. Usually `config.context?.route`
   * or the subapp's current location from its mount context.
   */
  initialPath?: string
  /**
   * Override the host API (testing / dev harness). Defaults to the `host`
   * export from `@wippy-fe/proxy`.
   */
  host?: typeof defaultHost
  /**
   * Override the event subscription API. Set to `null` to disable the
   * `@history` subscription entirely. Defaults to `on` from `@wippy-fe/proxy`.
   */
  on?: typeof defaultOn | null
}

/**
 * Canonical memory-router factory for Wippy subapps.
 *
 * Every subapp currently duplicates the same boilerplate:
 *   - create a memory history
 *   - prime it with an initial path from context
 *   - call `host.onRouteChanged` in `afterEach`
 *   - listen for `@history` events from the host and mirror them to the router
 *
 * This factory encapsulates that boilerplate so subapps become one-liners:
 *
 *   ```ts
 *   import { createAppRouter } from '@wippy-fe/router'
 *   import { routes } from './routes'
 *
 *   const router = createAppRouter(routes, {
 *     initialPath: appConfig.context?.route,
 *   })
 *   app.use(router)
 *   ```
 *
 * Memory history is hardcoded — srcdoc iframes do not support `createWebHistory`
 * (confirmed dead end — `window.location` is non-configurable in srcdoc, and
 * framework routers read `location.pathname` directly). Only memory-based
 * routing works inside child iframes.
 */
export function createAppRouter(
  routes: RouteRecordRaw[],
  options: CreateAppRouterOptions = {},
): Router {
  const host = options.host ?? defaultHost
  const on = options.on === undefined ? defaultOn : options.on

  const history = createMemoryHistory()
  if (options.initialPath)
    history.replace(options.initialPath)

  const router = createRouter({ history, routes })

  // Register this router with the link classifier so it can check own
  // routes before falling back to mount route / system route matching.
  setLocalRouter((path: string) => router.resolve(path))

  // Track the last navId applied from a parent-initiated update.
  // When the router navigates in response to a parent @history event,
  // suppress the resulting afterEach from sending CmdRouteChanged back up
  // (which would create an echo loop).
  let lastAppliedNavId: number | undefined

  router.afterEach((to) => {
    // If this navigation was triggered by a parent @history update,
    // pass the navId so the host can identify it as an echo and suppress.
    const navId = lastAppliedNavId
    lastAppliedNavId = undefined
    host.onRouteChanged(to.fullPath, navId)
  })

  if (on) {
    on('@history', ({ path, navId }: { path?: string, navId?: number }) => {
      if (!path)
        return
      if (navId !== undefined)
        lastAppliedNavId = navId
      const normalized = path.startsWith('/') ? path : `/${path}`
      if (router.currentRoute.value.fullPath !== normalized)
        router.push(normalized)
    })
  }

  return router
}
