import type { PropType } from 'vue'
import { host } from '@wippy-fe/proxy'
import { defineComponent, h } from 'vue'

/**
 * Explicit host-level navigation link. Use when you want to navigate
 * to a known host page regardless of the current nesting level.
 *
 * Unlike `AutoRouterLink` (which classifies links automatically),
 * `HostRouterLink` ALWAYS sends navigation to the host via postMessage.
 *
 * Use cases:
 *   - Inside a nav-owner child linking to a different host page
 *   - Anywhere you explicitly want host-level navigation
 *
 * Renders a real `<a>` for accessibility / right-click / SEO.
 * Left-click calls `host.navigate()`. Modifier keys (ctrl, meta, shift)
 * fall through to the browser default (open in new tab).
 */
export const HostRouterLink = defineComponent({
  name: 'WippyHostRouterLink',
  props: {
    to: {
      type: String as PropType<string>,
      required: true,
    },
  },
  setup(props, { slots }) {
    return () => h(
      'a',
      {
        href: props.to,
        onClick: (e: MouseEvent) => {
          if (e.defaultPrevented || e.button !== 0)
            return
          if (e.metaKey || e.altKey || e.ctrlKey || e.shiftKey)
            return
          e.preventDefault()
          host.navigate(props.to)
        },
      },
      slots.default?.(),
    )
  },
})
