import type { PropType } from 'vue'
import type { RouteLocationRaw } from 'vue-router'
import { host } from '@wippy-fe/proxy'
import { defineComponent, h } from 'vue'
import { useRouter, RouterLink as VueRouterLink } from 'vue-router'

/**
 * Drop-in replacement for Vue Router's `<RouterLink>` that classifies the
 * target href and dispatches intelligently:
 *
 *   - `host-nav`   → preventDefault + `host.navigate(href)` via postMessage
 *   - `child-nav`  → delegate to the real `<RouterLink>` (normal in-app nav)
 *   - `external`   → render an `<a>` with `target="_blank" rel="noopener"`
 *   - `ignore`     → render an `<a>` with a click-preventing handler
 *
 * Subapps migrate by changing a single import:
 *
 *   ```ts
 *   // before
 *   import { RouterLink } from 'vue-router'
 *
 *   // after
 *   import { RouterLink } from '@wippy-fe/router'
 *   ```
 *
 * Props are a compatible subset of vue-router's RouterLink. Slot API
 * mirrors the default (non-custom) slot of the real RouterLink.
 */
export const AutoRouterLink = defineComponent({
  name: 'WippyAutoRouterLink',
  props: {
    to: {
      type: [String, Object] as PropType<RouteLocationRaw>,
      required: true,
    },
    replace: {
      type: Boolean,
      default: false,
    },
    activeClass: {
      type: String,
      default: undefined,
    },
    exactActiveClass: {
      type: String,
      default: undefined,
    },
    ariaCurrentValue: {
      type: String as PropType<'page' | 'step' | 'location' | 'date' | 'time' | 'true' | 'false'>,
      default: 'page',
    },
    /**
     * For `external` kind: sets the anchor's target attribute.
     * Defaults to `_blank` with safe `rel`. Pass empty string for same-tab.
     */
    externalTarget: {
      type: String,
      default: '_blank',
    },
  },
  setup(props, { slots }) {
    const router = useRouter()

    return () => {
      const resolved = router.resolve(props.to)
      const classification = host.classifyLink(resolved.href)

      if (classification.kind === 'host-nav') {
        return h(
          'a',
          {
            'href': resolved.href,
            'onClick': (event: MouseEvent) => {
              if (event.defaultPrevented)
                return
              if (event.button !== 0)
                return
              if (event.metaKey || event.altKey || event.ctrlKey || event.shiftKey)
                return
              event.preventDefault()
              host.navigate(classification.normalizedPath ?? classification.href)
            },
            'aria-current': props.ariaCurrentValue,
          },
          slots.default?.(),
        )
      }

      if (classification.kind === 'external') {
        const isBlank = props.externalTarget === '_blank'
        return h(
          'a',
          {
            href: resolved.href,
            target: props.externalTarget || undefined,
            rel: isBlank ? 'noopener noreferrer' : undefined,
          },
          slots.default?.(),
        )
      }

      if (classification.kind === 'ignore') {
        return h(
          'a',
          {
            href: resolved.href || '#',
            onClick: (event: MouseEvent) => event.preventDefault(),
          },
          slots.default?.(),
        )
      }

      // child-nav → delegate to real vue-router RouterLink
      return h(
        VueRouterLink,
        {
          to: props.to,
          replace: props.replace,
          activeClass: props.activeClass,
          exactActiveClass: props.exactActiveClass,
          ariaCurrentValue: props.ariaCurrentValue,
        },
        slots.default
          ? { default: (scope: unknown) => slots.default?.(scope) }
          : undefined,
      )
    }
  },
})

/** @deprecated Use AutoRouterLink instead */
export const RouterLink = AutoRouterLink
